class Solution {
public:
    bool isRationalEqual(string s, string t) {
        auto parse = [](string& s) {
            int i = s.find('(');
            if (i == string::npos) return stod(s);
            string integer = s.substr(0, s.find('.'));
            string nonRepeating = s.substr(s.find('.') + 1, i - s.find('.') - 1);
            string repeating = s.substr(i + 1, s.find(')') - i - 1);
            double num = stod(integer + "." + nonRepeating);
            double rep = stod("0." + repeating);
            for (int j = 0; j < 10; j++) {
                num += rep / pow(10, nonRepeating.length() + j * repeating.length());
            }
            return num;
        };
        return abs(parse(s) - parse(t)) < 1e-9;
    }
};
